async function testSailingJsEndpoint() {
  const BASE = 'http://localhost:3001';
  const res = await fetch(BASE + '/api/sailing-js');
  assertEquals(res.status, 200, 'Should return 200');

  const contentType = res.headers.get('content-type') || '';
  assert(contentType.includes('javascript'), 'Should have JavaScript content type');

  const js = await res.text();
  assert(js.length > 30000, 'JS should be substantial (>30KB)');

  // Verify water detection functions are present
  assert(js.includes('function latLonToTilePixel'), 'Should have latLonToTilePixel');
  assert(js.includes('function tilePixelToLatLon'), 'Should have tilePixelToLatLon');
  assert(js.includes('function isWaterPixel'), 'Should have isWaterPixel');
  assert(js.includes('function loadTileToCanvas'), 'Should have loadTileToCanvas');
  assert(js.includes('function findNearestWater'), 'Should have findNearestWater');
  assert(js.includes('function validateAndSetBoatPosition'), 'Should have validateAndSetBoatPosition');

  // Verify event handlers use the validator
  assert(js.includes("validateAndSetBoatPosition(pos.lat, pos.lng, 'drag')"), 'Dragend should use validator');
  assert(js.includes("validateAndSetBoatPosition(e.latlng.lat, e.latlng.lng, 'click')"), 'Click should use validator');
  assert(js.includes("validateAndSetBoatPosition(pos.coords.latitude, pos.coords.longitude, 'geolocation')"), 'Geolocation should use validator');

  // Verify no old direct-set patterns remain
  assert(!js.includes("boatPosition = { lat: pos.lat, lon: pos.lng };\n      updateInfoBar();\n      refreshData();"), 
    'Old direct-set pattern in dragend should be removed');
}
